var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"로터스, 제5 격납고","JPN":"ロータス、第5格納庫","ENG":"Lotus, Hangar 5","TWN":"洛德斯，第5機庫"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"subtitle","speaker":null,"text":{"KOREA":"CSE Lv. 3.8","JPN":"CSE Lv.3.8","ENG":"CSE Lv. 3.8","TWN":"CSE Lv. 3.8"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"괜찮겠습니까?","JPN":"大丈夫ですか？","ENG":"Are you sure about this?","TWN":"這樣真的沒問題嗎？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"으, 응? 저 사람들을 여기로 불러들이는 것 말이야?","JPN":"う、うん？　あの人たちをここに呼ぶのが？","ENG":"H-huh? You mean inviting those people here?","TWN":"呃，嗯？你說把那些人叫到這裡嗎？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L9_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"괜찮지… 않을까?","JPN":"大丈夫……だと思う。","ENG":"It should be fine... I think?","TWN":"應該……沒問題吧？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"일단은 공인 카운터인 네가 있잖아.","JPN":"一応公認カウンターのファティマがいるじゃない。","ENG":"For starters, you are an Official Counter.","TWN":"反正這裡還有你這個公認的制裁者。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"아뇨, 그런 걸 걱정하는 게 아닙니다.","JPN":"いいえ、そっちの心配ではありません。","ENG":"No, that is not what I am worried about.","TWN":"不，這點你不用擔心。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L14_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"낯을 많이 가리는 시니어님께서 제대로 된 사회적 커뮤니케이션이 가능할지 걱정입니다.","JPN":"人見知りのシニア様が、ちゃんとした社会的コミュニケーションが取れるかが心配なのです。","ENG":"I am worried whether you, who are extremely shy, can handle proper social communication.","TWN":"我擔心平時很怕生的Senior者，是否能正常進行交流。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L15_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"지난번처럼 말 한마디 못 하고 대화형 인공지능으로 소통하신다던가…….","JPN":"この前のように一言も喋れず、会話型人工知能で疎通をするのは……","ENG":"Like last time, when you could not say a single word and tried to talk through a conversational AI...","TWN":"會不會像上次一樣一句話都說不出口，只靠對話型人工智慧交流之類的……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L16_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"야! 내, 내가 언제 그렇게까지 했어?!","JPN":"ちょっと！　そ、そこまでしてないよ！","ENG":"Hey! W-when did I ever go that far?!","TWN":" 喂！我、我什麼時候那麼誇張了？！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L17_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"그냥 몸이 좀 안 좋으니까 대신 말 좀 해달라고 한 거지!","JPN":"ちょっと具合が悪かったから、代わりに話してってお願いしただけ！","ENG":"I just wasn't feeling well, so I asked it to talk for me.","TWN":"我只是因為身體有點不舒服，才會找人代替我說話！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L18_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"몇 번이나 남 눈을 쳐다보는 걸 망설이다가 결국은 개인 작업실로 도망치면서까지 말입니까?","JPN":"何度も人と目を合わせるのをためらい、最後には個人作業室に逃げ込んでまでですか？","ENG":"You hesitated to make eye contact so many times, then ran to your private workshop in the end.","TWN":"您是說您看著別人猶豫了好幾次，最後逃回私人工作室後才說話嗎？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L19_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"시니어님의 큰 뜻을 알아차리지 못해서 유감이군요.","JPN":"なるほど。シニア様の意図を察せず、大変申し訳ありませんでした。","ENG":"My apologies for failing to grasp your grand intent.","TWN":"我沒察覺Senior者的用意真是太可惜了。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L20_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"씨이…….","JPN":"ちっ……","ENG":"Grr...","TWN":"哼……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L21_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"자기 목숨 달린 일이라면 어떻게든 회피하려고 하시는 시니어님이 왜 이번 부탁을 흔쾌히 승낙했는지 궁금하군요.","JPN":"自分の命がかかっていることになると、どんな手を使ってでも逃げようとするシニア様が、今回はなぜ要請にすんなり応じたのですか？","ENG":"You usually shy away when your life’s on the line. So why accept this request so easily?","TWN":"明明只要關係到自己性命的事都會想盡辦法逃避，我真好奇為什麼Senior這次會欣然答應。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L23_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"……별거 아니야.","JPN":"……大した理由はないよ。","ENG":"...It's nothing special.","TWN":"……沒什麼。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"네가 로터스의 시니어인가?","JPN":"お前がロータスのシニアか？","ENG":"You are Lotus's Senior?","TWN":"你是洛德斯的Senior嗎？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"그래. 내가 로터스의 시니어, 이졸데야.","JPN":"そう。私がロータスのシニア、イゾルデだよ。","ENG":"Yes. I am Isolde, Senior of Lotus.","TWN":"沒錯，我是洛德斯的Senior，伊索德。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"꼬마 아가씨 이름은 뭐야?","JPN":"お嬢ちゃん、名前はなんて言うの？","ENG":"What is your name?","TWN":"妳叫什麼名字？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"미래에 세상을 바꿀 공학자의 이름 정도는 미리 알고 싶은데.","JPN":"将来世界を変える工学者の名前、今から覚えておきたいな。","ENG":"I would like to know the name of the engineer who will change the world.","TWN":"我想先知道可以改變未來世界工程師的名字。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"LOTUS_ADMIN_NPC_GIRL","text":{"KOREA":"이졸데… 이졸데예요.","JPN":"イゾルデ……イゾルデです。","ENG":"Isolde... I'm Isolde.","TWN":"伊索德……我叫伊索德。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"이졸데. 예쁜 이름이네.","JPN":"イゾルデ。素敵な名前ね。","ENG":"Isolde. That's a pretty name.","TWN":"伊索德，真是個好聽的名字。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"선로전환기라는 장치의 시스템 구축을 준비하고 있다고 들었다.","JPN":"線路転換器という装置のシステム構築を準備していると聞いた。","ENG":"I hear you are preparing to build the system for a device called the Track Switcher.","TWN":"聽說你正在準備建立線路轉換器這個裝置的系統。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"분명 혼자서는 무리인 작업일 터.","JPN":"きっと一人では無理な作業のはず。","ENG":"It is surely too much for one person.","TWN":"這肯定是無法單獨完成的工作。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"우리는 너에게 기술을 지원하겠다.","JPN":"私たちが技術支援をしよう。","ENG":"We will provide technical support.","TWN":"我們會給你技術支援。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"너희는 범죄자잖아. 우리가 너흴 어떻게 믿어?","JPN":"あなたたちは犯罪者でしょ。何を根拠に信用しろっていうの？","ENG":"You're criminals. How are we supposed to trust you?","TWN":"你們是罪犯，憑什麼要相信你們？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"믿지 않아도 상관없다.","JPN":"信用せずとも構わない。","ENG":"Your trust is irrelevant.","TWN":"不相信也無所謂。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"너의 신뢰를 얻기 위한 행위에 들이는 시간은 무가치하니까.","JPN":"お前の信用を得るためにかける時間に価値はない。","ENG":"Time spent trying to earn it has no value.","TWN":"花時間去贏得你的信任毫無意義。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"공학자란 이론을 현실로 만드는 자.","JPN":"工学者は理論を現実にする者。","ENG":"An engineer turns theory into reality.","TWN":"工程師，是把理論化為現實的人。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_30"},{"id":"L49_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"자신의 이상을 실현할 기회가 왔음에도 이를 걷어차는 것은…….","JPN":"己の理想を実現するチャンスを自ら手放すのは……","ENG":"If you kick away a chance to realize your ideals...","TWN":"當有機會實現自己的理想卻放棄……."},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"결국 자신의 가치가 거기까지라는 것을 증명하는 셈일 테니.","JPN":"己の価値は所詮その程度だという証明に他ならない。","ENG":"You only prove that your worth extends no further.","TWN":"等於證明了自己的價值只到這裡而已。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"그럼 이졸데, 이거 하나만 기억해 줄 수 있니?","JPN":"じゃあイゾルデ、これだけは覚えていてくれる？","ENG":"Isolde, could you remember this one thing for me?","TWN":"伊索德，妳能幫我記住一句話嗎？"},"stage":{"bg":"OMEN_LOTUS_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"이 말을 간직하고 있다가, 꼭 세상을 지켜주길 바라.","JPN":"この言葉を忘れないで、世界を守ってね。","ENG":"Hold on to these words and use them to protect the world.","TWN":"希望妳能把它放在心裡，總有一天能守護世界。"},"stage":{"bg":"OMEN_LOTUS_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"<color=#ffd34c>공학자는 이론을 현실로 만드는 사람이야.</color>","JPN":"<color=#ffd34c>工学者は理論を現実にする人。</color>","ENG":"<color=#ffd34c>An engineer turns theory into reality.</color>","TWN":"<color=#ffd34c>工程師，是把理論化為現實的人。</color>"},"stage":{"bg":"OMEN_LOTUS_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"그 말…….","JPN":"その言葉……","ENG":"What you just said...","TWN":"那句話……"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"흥, 좋아. 얼마나 대단한 녀석들인지 확인해 보자고.","JPN":"ふん、まあいいさ。どれだけすごいか見せてもらうからね。","ENG":"Hmph. Fine. Let's see how impressive they really are.","TWN":"哼，好。我們就看看你們有多厲害吧。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"그 로봇이랑 기계수집가는 블랙 네트워크에서 유명한 공학 계통 범죄자들이야.","JPN":"あのロボットと機械収集家は、ブラックネットワーク上で結構知られている工学系犯罪者たち。","ENG":"That robot and Machine Collector are notorious engineering criminals on the Dark Network.","TWN":"那個機器人和機械收藏家在黑色網路可是知名的工程系統罪犯。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"분명 이번에 협력해 준다면 작업에 큰 진전이 있을 거야.","JPN":"協力してもらったら、作業も大きく進展するはず。","ENG":"If they really help us, this will push the work forward a lot.","TWN":"如果這次他們加入，工作一定能有重大進展。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"정리하자면, 시니어님의 공학적 탐구심 때문에 허락했다는 거로군요.","JPN":"つまり、シニア様の工学的探究心のために受け入れたということですね。","ENG":"So in short, you approved it because of your engineering curiosity.","TWN":"所以結論是因為Senior對工程的好奇心，才允許他們協助啊。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"그, 그렇게 말하면 내가 너무 매드 사이언티스트처럼 보이지 않나?","JPN":"そ、そういう言い方すると、まるで私がマッドサイエンティストみたいじゃない。","ENG":"P-putting that way makes me sound like some mad scientist.","TWN":"你這樣說的話，會、會不會讓我看起來太像瘋狂科學家了？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"내가 아까도 말했잖아.","JPN":"さっきも言ったでしょ。","ENG":"I told you earlier.","TWN":"我剛剛不也說過了。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"나랑 견줄 수 있는 천재가 한 명만 더 있으면 작업의 속도가 달라질 거라고.","JPN":"私と同じぐらいの天才がもう一人いれば、作業のスピードは桁違いになるって。","ENG":"With just one more genius on my level, the pace of work would change completely.","TWN":"如果再有一個能跟我比擬的天才，工作速度會完全不同。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"검은 평의회의 사람들이라면 분명 내가 모르는 지식을 갖고 있을지도 모르지.","JPN":"黒い評議会の人なら、私の知らない知識を持ってるかもしれないしね。","ENG":"If they are from the Dark Council, they may know things I don't.","TWN":"評議會的人也許擁有我不知道的知識。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"후, 후후… 기대되는걸?","JPN":"ふ、ふふ……楽しみだなあ。","ENG":"Ha, Haha... I'm so excited.","TWN":" 呼、呼呼……真令人期待呢？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"시니어님! ARC-EX에서 긴급한 연락입니다!","JPN":"シニア！　ARC-EXから緊急連絡です！","ENG":"Senior! Emergency call from ARC-EX!","TWN":" Senior！ARC-EX 收到緊急聯絡！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"ARC-EX… 구 알렉산드리아에도 침식체의 침공이 시작되었다고 합니다!","JPN":"ARC-EX……旧アレクサンドリアにも侵食体が攻め入ってきたとのことです！","ENG":"ARC-EX... Former Alexandria reports C.O.s have begun their invasion!","TWN":"據說ARC-EX…舊亞歷山卓也開始遭受侵蝕體入侵！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"지원 요청을 보내오고 있습니다만, 관리국이 소집한 병력으로는 모든 도시를 지원하기 어렵습니다!","JPN":"支援要請を送ってきていますが、管理局が招集した兵力では、すべての都市に支援を送るのは無理です！","ENG":"They are requesting support, but with the forces we assembled, we can't cover every city!","TWN":"雖然已經請求支援，但管理局徵召的兵力無法支援所有城市！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"젠장, 침식파 억제기도 역시 무용지물인 건가…….","JPN":"くそ、侵食波抑制装置も使い物にならないのか……","ENG":"Damn it, so the Corruption Inhibitor is useless after all...","TWN":"該死，侵蝕波抑制器也無用武之地嗎……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_BOW"},{"id":"L35_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"ARC-EX는 이터니움을 축적한 광산 도시입니다.","JPN":"ARC-EXはエタニウムを蓄積している鉱山都市です。","ENG":"ARC-EX is a mining city that accumulates Eternium.","TWN":"ARC-EX是積累永恆之金的礦山城市。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"근처 사막에서 침식 현상이 자주 발생하거든요.","JPN":"近くの砂漠で侵食現象が頻繁に発生しているものでして。","ENG":"Counterside Effects frequently occur in the surrounding desert.","TWN":"附近沙漠經常發生侵蝕現象。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"로터스에서 소모되는 이터니움의 절반은 그곳에서 생산된다고 해도 과언이 아니죠.","JPN":"ロータスで消費されるエタニウムの半分はそこで生産されていると言っても過言ではありません。","ENG":"Half the Eternium Lotus consumes practically comes from there.","TWN":"可以說洛德斯消耗的大半永恆之金都來自那裡。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"전략적으로 유용한 곳입니다. 반드시 확보하는 것이 좋을 겁니다.","JPN":"戦略的な価値が高い地域です。必ず確保したほうがいいでしょう。","ENG":"It is strategically valuable. We should secure it at all costs.","TWN":"戰略上非常重要，務必確保。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"근처에 도움을 요청할 태스크포스나 용병이 없는 거야?","JPN":"その近くには協力してもらえそうなタスクフォースや傭兵はいないの？","ENG":"Is there no TASKFORCE or mercenary unit nearby we can hire?","TWN":"附近沒有能派去幫忙的特遣勢力或傭兵嗎？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"보수는 후하게 쳐준다고 해.","JPN":"報酬は弾むって言って。","ENG":"Tell them we will pay generously.","TWN":"說酬勞很豐厚喔。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L42_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"그곳만큼이나 이곳도 중요하니까 파티마는 움직일 수 없어.","JPN":"そこと同じぐらいここも重要だから、ファティマは動かせないの。","ENG":"You can't go, Fatima. This place is just as important.","TWN":"但這裡跟那裡一樣重要，法蒂瑪不能動。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L44_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"도시를 지켜야 할 책임이 있는 시니어가 대놓고 그런 발언을 하시다니.","JPN":"都市を守る責任があるシニアが、堂々とそんな発言をされるとは。","ENG":"For a Senior charged with defending the city, that is a very candid thing to say.","TWN":"必須負責守護城市的Senior者竟然冠冕堂皇說出這種話。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L45_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"이 파티마, 실망하진 않았습니다.","JPN":"このファティマ、がっかり……していません。","ENG":"I, Fatima, am not disappointed.","TWN":"這法蒂瑪可沒讓我失望。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L46_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"원래 그러셨던 분이니까요.","JPN":"もともとそういう方でしたから。","ENG":"It is how you always were.","TWN":"您本來就是這樣的人。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L48_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"그, 그렇게까지 말할 건 아니잖아!","JPN":"そ、そこまで言うことないじゃない！","ENG":"Y-you did not have to say it like that!","TWN":"那、那也不用說得這麼誇張吧！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L50_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"그, 그게… 모두 지원 요청을 했지만 거절당했습니다.","JPN":"そ、その……支援要請を送れるだけ送りましたが、全部断られました。","ENG":"W-well... we asked everyone for support and were refused.","TWN":"那、那是……雖然大家都請求支援，但都被拒絕了。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"다들 각자 맡은 구역에서 일시 다발적으로 침식 재난이 일어나고 있다고 하더군요.","JPN":"皆一様に、担当区域で同時多発的に侵食災害が起きていると言っていました。","ENG":"They say simultaneous Corruption disasters are breaking out in all their sectors.","TWN":"據說每個人負責的區域都同時爆發侵蝕災害。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"뭐어어?","JPN":"えええ？","ENG":"Whaaat?","TWN":"什麼？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"그, 그럼 이터니움을 포기하고 후퇴를…….","JPN":"じゃ、じゃあエタニウムを諦めて、撤退を……","ENG":"Th-then we should give up on the Eternium and retreat–","TWN":"那、那麼要放棄永恆之金撤退嗎……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"아, 아니야. 그렇게 되면 그 이터니움을 침식체들이 어떻게 이용할지 모르잖아.","JPN":"いや、違う。そうなると侵食体があのエタニウムをどう利用してくるか分からない。","ENG":"No. If we do that, who knows how the C.O.s will use it.","TWN":"不，不行。如果那麼做，說不定侵蝕體可能會利用永恆之金做什麼事。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"그러면 차라리 파티마를…….","JPN":"だったらファティマを送ったほうが……","ENG":"In that case, maybe Fatima should–","TWN":"還不如派法蒂瑪……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"시니어님.","JPN":"シニア様。","ENG":"Senior.","TWN":"Senior。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L9_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"침착하셔야 합니다.","JPN":"落ち着いてください。","ENG":"You must stay calm.","TWN":"請保持冷靜。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"내, 내가 여기서 뭘 어떻게 할 수 있지?","JPN":"こ、こんな状況で、私に何ができる？","ENG":"W-what can I even do from here?","TWN":"我、我在這裡能做什麼呢？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"나는…….","JPN":"私は……","ENG":"I...","TWN":"我……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_QM","text":{"KOREA":"그렇게 사람을 몰아붙이면 침착하게 생각할 것도 못 하지 않으려나?","JPN":"そうやって追い込んじゃったら、余計に落ち着けないんじゃない？","ENG":"If you push people that hard, how are they supposed to think straight?","TWN":"你這麼逼人，就不能冷靜思考一下嗎？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L16_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"음? 당신은……?","JPN":"ん？　あなたは……？","ENG":"Mm? Who are you...?","TWN":"嗯？妳是……？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"사람은 당근과 채찍이 중요한 법이거든.","JPN":"人には飴と鞭が必要なのよ。","ENG":"People need both carrot and stick. That's how it works.","TWN":"人最需要胡蘿蔔和鞭子。"},"stage":{"bg":"ROOM_02","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};